func bpTierName(tier int) string {
	switch tier {
	case 0:
		return "normal"
	case 1:
		return "throttle"
	case 2:
		return "simplify"
	case 3:
		return "disconnect"
	default:
		return fmt.Sprintf("tier-%d", tier)
	}
}

func bpTierBadgeClass(tier int) string {
	switch tier {
	case 0:
		return "badge-success"
	case 1:
		return "badge-warning"
	case 2:
		return "badge-accent"
	case 3:
		return "badge-error"
	default:
		return "badge-ghost"
	}
}

func bpTopicPub(m tavern.BrokerMetrics, topic string) int64 {
	if ts, ok := m.TopicStats[topic]; ok {
		return ts.Published
	}
	return 0
}

func bpTopicDrop(m tavern.BrokerMetrics, topic string) int64 {
	if ts, ok := m.TopicStats[topic]; ok {
		return ts.Dropped
	}
	return 0
}

func bpBatchLabel(d time.Duration) string {
	ms := d.Milliseconds()
	if ms == 0 {
		return "raw"
	}
	return fmt.Sprintf("%dms", ms)
}

func bpStripSimplified(msg string) string {
	return strings.TrimPrefix(msg, "[simplified] ")
}

func bpTopicBadge(topic string) string {
	switch topic {
	case "bp-alpha":
		return "badge-primary"
	case "bp-beta":
		return "badge-secondary"
	case "bp-gamma":
		return "badge-accent"
	default:
		return "badge-ghost"
	}
}

func bpTierIndicatorClass(tierName string) string {
	switch tierName {
	case "normal":
		return "bg-success/10 border border-success/30 text-success"
	case "throttle":
		return "bg-warning/10 border border-warning/30 text-warning"
	case "simplify":
		return "bg-orange-500/10 border border-orange-500/30 text-orange-500"
	case "disconnect":
		return "bg-error/10 border border-error/30 text-error"
	default:
		return "bg-base-200 border border-base-300 text-base-content/50"
	}
}

func bpTierIndicatorBadge(tierName string) string {
	switch tierName {
	case "normal":
		return "badge-success"
	case "throttle":
		return "badge-warning"
	case "simplify":
		return "badge-accent"
	case "disconnect":
		return "badge-error"
	default:
		return "badge-ghost"
	}
}

func bpTierExplanation(tierName string) string {
	switch tierName {
	case "normal":
		return "Full-fidelity delivery. All messages arrive as published."
	case "throttle":
		return "Subscriber is lagging. Every other message is being skipped."
	case "simplify":
		return "Degraded delivery. Messages are simplified to reduce load."
	case "disconnect":
		return "Subscriber evicted. Connection was too far behind."
	default:
		return "Unknown tier state."
	}
}

